#!/usr/bin/env python3
"""Sessions 161-170 complete build. Run from ~/LagnaMaster: python3 build_s161_170.py"""
import os, re, ast
if not os.path.isfile("requirements.txt"):
    print("ERROR: run from LagnaMaster root"); exit(1)

def write(path, content):
    os.makedirs(os.path.dirname(path) if os.path.dirname(path) else ".", exist_ok=True)
    with open(path, "w") as f: f.write(content)
    print("  WRITE " + path)

def patch(path, old, new, label):
    if not os.path.isfile(path): print("  SKIP (missing) " + path); return False
    with open(path) as f: s = f.read()
    if old not in s: print("  SKIP (no match) " + path + " [" + label + "]"); return False
    with open(path, "w") as f: f.write(s.replace(old, new, 1))
    print("  PATCH " + path + " [" + label + "]"); return True

def append_guard(path, text, guard, label):
    if not os.path.isfile(path): return
    with open(path) as f: s = f.read()
    if guard in s: print("  SKIP " + path + " [" + label + "]"); return
    with open(path, "a") as f: f.write("\n" + text)
    print("  APPEND " + path + " [" + label + "]")

